import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"虚哭神去","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/虚哭神去.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/虚哭神去.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/虚哭神去.md"};function l(_,r,b,i,p,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"虚哭神去",tabindex:"-1"},[s("虚哭神去 "),e("a",{class:"header-anchor",href:"#虚哭神去","aria-label":'Permalink to "虚哭神去"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"绯红庆典040")])])],-1),o('<h1 id="虚哭神去-1" tabindex="-1">虚哭神去 <a class="header-anchor" href="#虚哭神去-1" aria-label="Permalink to &quot;虚哭神去&quot;">​</a></h1><p>虚哭神去</p><p>这一血鬼术实质是以你自身血肉凝结而出的武器，因此不会提供属性。虚哭神去整体由血管与肌肉纤维组成，这些血管与肌肉似乎正有生命般搏动着，刀身上排列的大大小小的布满血丝的眼球随着使用者的挥舞而转动。<br> B+4000<br> 武器伤害：18L<br> 武器类型：武士刀<br> 武器体积：3<br> 使用专业：刀<br> 特性：血肉合一、 嫉恨、妒目<br> 【血肉合一】：当你强化这一血鬼术后，你便可以花招动作将自身血肉分离出自己血肉并构成虚哭神去。这一武器即是你的血肉，你无法将其作为投掷武器丢出或是进行改造，当其脱离你的触及范围后，其将失去作用并迅速凋亡坏死，这一武器受到攻击时按照你自身受到攻击一般进行处理。<br> 同样的，这一武器无法被击落，即使持有武器的肢体掉落，你依然可以花招动作将其重塑至其他肢体上。血肉构成的刀刃具有诡异的延展性，能够自如的收缩伸展，在使用这一武器时，你的触及范围会提升耐力属性*2米。<br> 【妒目】：每轮一次，当你受到攻击时，若你能够以视觉对攻击者进行模糊定位，则你可以令这次攻击重新掷骰，以重骰后的结果取代原先结果。<br> 【嫉恨】：虚哭神去是你内心的妒火的具象产物，当你受创时，它将不断的改变你的肉身，随着你的恨意在体内疯狂生长，无数的血肉刀刃将狰狞的破体而出，直至能够撕碎能够伤害、胆敢伤害你的一切！<br> 当你受到等同于你耐力属性点的严重伤害后，你按次序获得以下效果，每轮只会获得一次对应效果。获得的效果会持续一个场景。<br> 1：武器伤害提升3点，每轮一次，你在以此武器进行招架时，若这次攻击为近战攻击且未对你造成任何伤害或异常点数，则对攻击者进行反击造成等同招架抵消出目点的挥砍严重伤害。<br> 2：此武器的触及范围提升耐力属性米。你的攻击会同时影响到触及范围内的所有敌方单位。<br> 3：你失去至多耐力属性点的洞察防御，获得等同失去洞察防御的武器伤害。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
